import React, { useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import type { useAuth } from "../hooks/useAuth";

type AuthGateProps = {
  authHook: ReturnType<typeof useAuth>;
  logoSrc: string;
  colorNavy: string;
  colorGold: string;
  colorSky: string;
  colorCream: string;
};

type Mode = "login" | "register" | "forgot";
const VISION_LOGO = "data:image/png;base64,";

export function AuthGate({ authHook, logoSrc, colorNavy, colorGold, colorSky, colorCream }: AuthGateProps) {
  const { authState, error, signIn, signUp, resetPassword } = authHook;
  const [mode, setMode] = useState<Mode>("login");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [cabinetName, setCabinetName] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [successMsg, setSuccessMsg] = useState("");
  const [localError, setLocalError] = useState("");

  const displayError = localError || error;

  const handleLogin = async () => {
    setLocalError("");
    setLoading(true);
    await signIn(email, password);
    setLoading(false);
  };

  const handleRegister = async () => {
    setLocalError("");
    if (!cabinetName.trim()) { setLocalError("Veuillez saisir le nom de votre cabinet."); return; }
    if (password.length < 8) { setLocalError("Le mot de passe doit faire au moins 8 caractères."); return; }
    if (password !== confirmPassword) { setLocalError("Les mots de passe ne correspondent pas."); return; }
    setLoading(true);
    const ok = await signUp(email, password, cabinetName);
    setLoading(false);
    if (ok) {
      setSuccessMsg("Compte créé ! Vérifiez votre email pour confirmer votre inscription.");
      setMode("login");
    }
  };

  const handleForgot = async () => {
    setLocalError("");
    if (!email) { setLocalError("Entrez votre email."); return; }
    setLoading(true);
    const ok = await resetPassword(email);
    setLoading(false);
    if (ok) setSuccessMsg("Email de réinitialisation envoyé !");
  };

  const SURFACE_CREAM = "#FBF7F0";

  const geoKeyframes = `
    @keyframes float1 { 0%,100% { transform: translate(0,0) rotate(0deg); } 50% { transform: translate(20px,-15px) rotate(12deg); } }
    @keyframes float2 { 0%,100% { transform: translate(0,0) rotate(0deg); } 50% { transform: translate(-15px,20px) rotate(-8deg); } }
    @keyframes float3 { 0%,100% { transform: translate(0,0) rotate(0deg); } 50% { transform: translate(10px,25px) rotate(15deg); } }
    @keyframes float4 { 0%,100% { transform: translate(0,0) rotate(0deg); } 50% { transform: translate(-20px,-10px) rotate(-12deg); } }
    @keyframes float5 { 0%,100% { transform: translate(0,0) rotate(0deg); } 50% { transform: translate(15px,10px) rotate(6deg); } }
  `;

  const shapes: React.CSSProperties[] = [
    { position: "absolute", top: "8%", left: "5%", width: 120, height: 120, borderRadius: "50%", background: colorNavy, opacity: 0.06, animation: "float1 12s ease-in-out infinite" },
    { position: "absolute", bottom: "12%", right: "8%", width: 160, height: 160, borderRadius: "50%", background: colorNavy, opacity: 0.05, animation: "float2 14s ease-in-out infinite" },
    { position: "absolute", top: "20%", right: "12%", width: 80, height: 140, borderRadius: 16, background: colorGold, opacity: 0.08, animation: "float3 10s ease-in-out infinite" },
    { position: "absolute", bottom: "25%", left: "8%", width: 100, height: 60, borderRadius: 12, background: colorGold, opacity: 0.07, animation: "float4 11s ease-in-out infinite" },
    { position: "absolute", top: "55%", left: "15%", width: 70, height: 70, borderRadius: 14, background: colorSky, opacity: 0.06, animation: "float5 13s ease-in-out infinite" },
    { position: "absolute", top: "10%", right: "25%", width: 50, height: 50, borderRadius: 10, background: colorSky, opacity: 0.07, animation: "float1 15s ease-in-out infinite" },
    { position: "absolute", bottom: "35%", right: "20%", width: 40, height: 40, borderRadius: "50%", background: colorGold, opacity: 0.1, animation: "float2 9s ease-in-out infinite" },
    { position: "absolute", top: "40%", left: "3%", width: 55, height: 55, borderRadius: "50%", background: colorNavy, opacity: 0.04, animation: "float3 16s ease-in-out infinite" },
    { position: "absolute", bottom: "5%", left: "30%", width: 180, height: 40, borderRadius: 20, background: colorNavy, opacity: 0.04, animation: "float4 14s ease-in-out infinite" },
    { position: "absolute", top: "3%", right: "3%", width: 90, height: 90, borderRadius: "50%", background: colorSky, opacity: 0.05, animation: "float5 11s ease-in-out infinite" },
  ];

  return (
    <div className="min-h-screen flex flex-col items-center justify-center px-4" style={{ background: SURFACE_CREAM, position: "relative", overflow: "hidden" }}>
      <style>{geoKeyframes}</style>
      {shapes.map((style, i) => <div key={i} style={style} />)}

      {/* Logo + titre */}
      <div className="flex flex-col items-center mb-10 gap-4" style={{ position: "relative", zIndex: 1 }}>
        <img src={VISION_LOGO} alt="Vision Ecopatrimoine" className="h-28 w-auto object-contain drop-shadow-lg" />
        <div className="text-center">
          <div className="text-3xl font-bold tracking-tight" style={{ color: colorNavy }}>Vision Ecopatrimoine</div>
          <div className="text-sm font-medium mt-1.5 tracking-wide" style={{ color: colorSky }}>Logiciel de gestion patrimoniale</div>
        </div>
      </div>

      {/* Carte */}
      <Card className="w-full max-w-md rounded-3xl border-0" style={{ position: "relative", zIndex: 1, boxShadow: "0 8px 40px rgba(16,27,59,0.10), 0 2px 12px rgba(227,175,100,0.08)" }}>
        <CardContent className="p-8 space-y-5">

          {/* Titre mode */}
          <div className="text-center mb-2">
            <h2 className="text-lg font-bold" style={{ color: colorNavy }}>
              {mode === "login" && "Connexion"}
              {mode === "register" && "Créer un compte"}
              {mode === "forgot" && "Mot de passe oublié"}
            </h2>
            {mode === "register" && (
              <p className="text-xs text-slate-500 mt-1">Accès réservé aux CGP partenaires</p>
            )}
          </div>

          {/* Message succès */}
          {successMsg && (
            <div className="rounded-xl px-4 py-3 text-sm font-medium text-emerald-700 bg-emerald-50 border border-emerald-200">
              ✓ {successMsg}
            </div>
          )}

          {/* Message erreur */}
          {displayError && (
            <div className="rounded-xl px-4 py-3 text-sm font-medium text-red-700 bg-red-50 border border-red-200">
              {displayError}
            </div>
          )}

          {/* Mode hors-ligne */}
          {authState === "grace" && (
            <div className="rounded-xl px-4 py-3 text-sm bg-amber-50 border border-amber-200 text-amber-800">
              ⚠️ Mode hors-ligne — connexion internet requise dans les 72h
            </div>
          )}

          {/* Champ cabinet (inscription) */}
          {mode === "register" && (
            <div className="space-y-1">
              <Label className="text-xs font-semibold tracking-wide" style={{ color: colorSky }}>NOM DU CABINET</Label>
              <Input
                value={cabinetName}
                onChange={e => setCabinetName(e.target.value)}
                placeholder="Ex : Dupont Patrimoine"
                className="rounded-xl text-sm"
                style={{ borderColor: "rgba(227,175,100,0.3)", background: "rgba(255,255,255,0.98)" }}
              />
            </div>
          )}

          {/* Email */}
          <div className="space-y-1">
            <Label className="text-xs font-semibold tracking-wide" style={{ color: colorSky }}>EMAIL</Label>
            <Input
              type="email"
              value={email}
              onChange={e => setEmail(e.target.value)}
              onKeyDown={e => e.key === "Enter" && mode === "login" && handleLogin()}
              placeholder="votre@email.com"
              className="rounded-xl text-sm"
              style={{ borderColor: "rgba(227,175,100,0.3)", background: "rgba(255,255,255,0.98)" }}
            />
          </div>

          {/* Mot de passe */}
          {mode !== "forgot" && (
            <div className="space-y-1">
              <Label className="text-xs font-semibold tracking-wide" style={{ color: colorSky }}>MOT DE PASSE</Label>
              <Input
                type="password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                onKeyDown={e => e.key === "Enter" && mode === "login" && handleLogin()}
                placeholder={mode === "register" ? "8 caractères minimum" : "••••••••"}
                className="rounded-xl text-sm"
                style={{ borderColor: "rgba(227,175,100,0.3)", background: "rgba(255,255,255,0.98)" }}
              />
            </div>
          )}

          {/* Confirmation mot de passe (inscription) */}
          {mode === "register" && (
            <div className="space-y-1">
              <Label className="text-xs font-semibold tracking-wide" style={{ color: colorSky }}>CONFIRMER LE MOT DE PASSE</Label>
              <Input
                type="password"
                value={confirmPassword}
                onChange={e => setConfirmPassword(e.target.value)}
                placeholder="••••••••"
                className="rounded-xl text-sm"
                style={{ borderColor: "rgba(227,175,100,0.3)", background: "rgba(255,255,255,0.98)" }}
              />
            </div>
          )}

          {/* Bouton action */}
          <Button
            onClick={mode === "login" ? handleLogin : mode === "register" ? handleRegister : handleForgot}
            disabled={loading || !email}
            className="w-full rounded-xl h-11 font-semibold text-sm shadow-md mt-2"
            style={{ background: `linear-gradient(135deg, ${colorNavy} 0%, ${colorSky} 100%)`, color: "#fff" }}
          >
            {loading ? "..." : mode === "login" ? "Se connecter" : mode === "register" ? "Créer mon compte" : "Envoyer le lien"}
          </Button>

          {/* Liens secondaires */}
          <div className="flex flex-col items-center gap-2 pt-1 text-xs text-slate-500">
            {mode === "login" && (
              <>
                <button onClick={() => { setMode("forgot"); setLocalError(""); setSuccessMsg(""); }} className="hover:underline hover:text-slate-700">
                  Mot de passe oublié ?
                </button>
                <button onClick={() => { setMode("register"); setLocalError(""); setSuccessMsg(""); }} className="hover:underline hover:text-slate-700">
                  Pas encore de compte ? S'inscrire
                </button>
              </>
            )}
            {(mode === "register" || mode === "forgot") && (
              <button onClick={() => { setMode("login"); setLocalError(""); setSuccessMsg(""); }} className="hover:underline hover:text-slate-700">
                ← Retour à la connexion
              </button>
            )}
          </div>

        </CardContent>
      </Card>

      <p className="text-xs text-slate-400 mt-6" style={{ position: "relative", zIndex: 1 }}>© Vision Ecopatrimoine — Données stockées localement</p>
    </div>
  );
}
